using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

if (string.IsNullOrWhiteSpace(openAiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// --- Shared state for the note-taking tool ---
var notebook = new List<string>();

// --- Tool definitions ---
[Description("Search the web for information on a query. Returns a list of search result snippets.")]
async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    // Use DuckDuckGo Instant Answer API (no key required)
    var encoded = Uri.EscapeDataString(query);
    var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

    try
    {
        var response = await http.GetFromJsonAsync<JsonElement>(url);
        var results = new List<string>();

        // Abstract text (main answer)
        var abstractText = response.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
            results.Add($"[Summary] {abstractText}");

        // Related topics
        if (response.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text))
                    results.Add($"[Related] {text.GetString()}");
            }
        }

        if (results.Count == 0)
            return $"No detailed results found for '{query}'. Try rephrasing the search.";

        return string.Join("\n\n", results);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Save a research note. Use this to record important findings as you research.")]
string TakeNote(
    [Description("The note content to save")] string note)
{
    notebook.Add(note);
    return $"Note saved (total notes: {notebook.Count}).";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    if (notebook.Count == 0)
        return "No notes have been saved yet.";

    return string.Join("\n---\n",
        notebook.Select((n, i) => $"Note {i + 1}: {n}"));
}

// --- Build the AI chat client with tools ---
var client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Get topic from user ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n{"",0}{new string('─', 40)}");

// --- Agent system prompt ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research a given topic thoroughly using the tools available.

        Strategy:
        1. Search the web for the topic using multiple relevant queries.
        2. Take notes on the most important findings as you go.
        3. After gathering enough information (at least 2-3 searches), retrieve your notes.
        4. Provide a well-structured summary with key findings, organized by subtopic.

        Be thorough but concise. Cite the information you find. Use the note-taking tool
        to track facts so you don't lose them between searches.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

// --- Run the agent loop ---
Console.WriteLine();
var response = await client.GetResponseAsync(messages, chatOptions);
Console.WriteLine(response.Text);

// --- Show collected notes ---
if (notebook.Count > 0)
{
    Console.WriteLine($"\n{"",0}{new string('─', 40)}");
    Console.WriteLine($"📝 Research notes collected: {notebook.Count}");
}

return 0;

